{
  "question": "Find all Java source files in apache/kafka that validate SASL mechanism configuration at broker startup: sasl.enabled.mechanisms validation, JAAS config presence check, and mechanism-specific configuration validation (SCRAM, GSSAPI, OAUTHBEARER).",
  "repo": "github.com/sg-evals/kafka--0753c489",
  "files": [
    {
      "path": "clients/src/main/java/org/apache/kafka/common/network/ChannelBuilders.java",
      "role": "sasl.enabled.mechanisms validation + JAAS config presence check (entry point)",
      "relevant_symbols": [
        {
          "symbol": "channelBuilderConfigs",
          "lines": "135-140",
          "description": "Iterates over sasl.enabled.mechanisms list and calls JaasContext.loadServerContext() for each mechanism, triggering JAAS config presence checks for every enabled mechanism at broker startup."
        }
      ],
      "validation_categories": [
        "sasl.enabled.mechanisms validation",
        "JAAS config presence check"
      ]
    },
    {
      "path": "clients/src/main/java/org/apache/kafka/common/security/JaasContext.java",
      "role": "JAAS config presence check",
      "relevant_symbols": [
        {
          "symbol": "loadServerContext",
          "lines": "62-75",
          "description": "Loads the JAAS context for a specific mechanism on the server side. Looks up the mechanism-prefixed sasl.jaas.config property (e.g. listener.name.<listener>.<mechanism>.sasl.jaas.config) and delegates to load(). Warns if the unprefixed sasl.jaas.config is set instead."
        },
        {
          "symbol": "load",
          "lines": "91-130",
          "description": "Validates that a JAAS configuration entry exists for the given context name. Throws IllegalArgumentException if no login module entry is found in the JAAS configuration, enforcing the JAAS config presence requirement."
        }
      ],
      "validation_categories": [
        "JAAS config presence check"
      ]
    },
    {
      "path": "clients/src/main/java/org/apache/kafka/common/network/SaslChannelBuilder.java",
      "role": "Mechanism-specific configuration validation (SCRAM, GSSAPI, OAUTHBEARER)",
      "relevant_symbols": [
        {
          "symbol": "configure",
          "lines": "140-182",
          "description": "Called at broker startup for each SASL-enabled listener. Invokes createServerCallbackHandlers() to instantiate and configure mechanism-specific callback handlers, triggering per-mechanism validation for all enabled mechanisms."
        },
        {
          "symbol": "createServerCallbackHandlers",
          "lines": "210-260",
          "description": "Dispatches mechanism-specific callback handler creation: uses ScramServerCallbackHandler for SCRAM-SHA-256/SCRAM-SHA-512, KerberosClientCallbackHandler for GSSAPI, OAuthBearerUnsecuredValidatorCallbackHandler (default) or a custom handler for OAUTHBEARER, and PlainServerCallbackHandler for PLAIN. Each handler's configure() is called, validating mechanism-specific settings."
        },
        {
          "symbol": "defaultLoginClass",
          "lines": "349-355",
          "description": "Selects the Login implementation based on enabled mechanisms: KerberosLogin for GSSAPI (which validates sasl.kerberos.service.name), OAuthBearerRefreshingLogin for OAUTHBEARER, and AbstractLogin for others."
        }
      ],
      "validation_categories": [
        "mechanism-specific configuration validation (SCRAM)",
        "mechanism-specific configuration validation (GSSAPI)",
        "mechanism-specific configuration validation (OAUTHBEARER)"
      ]
    },
    {
      "path": "clients/src/main/java/org/apache/kafka/common/security/authenticator/SaslServerAuthenticator.java",
      "role": "sasl.enabled.mechanisms validation",
      "relevant_symbols": [
        {
          "symbol": "SaslServerAuthenticator",
          "lines": "179-181",
          "description": "Constructor validates that the sasl.enabled.mechanisms list is non-null and non-empty, throwing IllegalArgumentException('No SASL mechanisms are enabled') if the list is absent or empty. Also validates that callback handlers and login subjects are present for each mechanism."
        }
      ],
      "validation_categories": [
        "sasl.enabled.mechanisms validation"
      ]
    },
    {
      "path": "clients/src/main/java/org/apache/kafka/common/security/kerberos/KerberosLogin.java",
      "role": "GSSAPI-specific configuration validation",
      "relevant_symbols": [
        {
          "symbol": "configure",
          "lines": "85-94",
          "description": "Called during broker startup when GSSAPI is an enabled mechanism. Reads Kerberos-specific configs (ticket renew window, jitter, min time before relogin, kinit command) and calls getServiceName() to validate the service name."
        },
        {
          "symbol": "getServiceName",
          "lines": "289-305",
          "description": "Validates the GSSAPI service name configuration. Checks both the JAAS config entry option and the sasl.kerberos.service.name Kafka config. Throws IllegalArgumentException if both are set with conflicting values, or if neither is set ('No serviceName defined in either JAAS or Kafka config')."
        }
      ],
      "validation_categories": [
        "mechanism-specific configuration validation (GSSAPI)"
      ]
    },
    {
      "path": "clients/src/main/java/org/apache/kafka/common/config/internals/BrokerSecurityConfigs.java",
      "role": "Configuration constant definitions",
