      "relevant_symbols": [
        {
          "symbol": "channelBuilderConfigs",
          "lines": "135-140",
          "description": "Iterates over sasl.enabled.mechanisms list and calls JaasContext.loadServerContext() for each mechanism, triggering JAAS config presence checks for every enabled mechanism at broker startup."
        }
      ],
      "validation_categories": [
        "sasl.enabled.mechanisms validation",
        "JAAS config presence check"
      ]
    },
