      "path": "clients/src/main/java/org/apache/kafka/common/security/JaasContext.java",
      "role": "JAAS config presence check",
      "relevant_symbols": [
        {
          "symbol": "loadServerContext",
          "lines": "62-75",
          "description": "Loads the JAAS context for a specific mechanism on the server side. Looks up the mechanism-prefixed sasl.jaas.config property (e.g. listener.name.<listener>.<mechanism>.sasl.jaas.config) and delegates to load(). Warns if the unprefixed sasl.jaas.config is set instead."
        },
        {
          "symbol": "load",
