arguments.new_str:
{
  "symbol": "configure",
  "lines": "140-186",
  "description": "Called at broker startup for each SASL-enabled listener. Invokes createServerCallbackHandlers() (line 145) to instantiate mechanism-specific callback handlers, then calls each handler's configure() (lines 149-152) passing the JAAS config entries, then acquires a LoginManager per mechanism (lines 166-175) which triggers KerberosLogin.configure() for GSSAPI."
},
{
  "symbol": "createServerCallbackHandlers",
  "lines": "317-336",
  "description": "Iterates over all enabled mechanisms and dispatches to the correct server-side callback handler: PlainServerCallbackHandler for PLAIN, ScramServerCallbackHandler for SCRAM-SHA-256/SCRAM-SHA-512, OAuthBearerUnsecuredValidatorCallbackHandler (default) or a custom class for OAUTHBEARER, and SaslServerCallbackHandler for GSSAPI and others. Each handler is stored in saslCallbackHandlers and later configured via configure()."
},
{
  "symbol": "defaultLoginClass",
  "lines": "349-355",
  "description": "Selects the Login implementation based on enabled mechanisms: KerberosLogin for GSSAPI (which validates sasl.kerberos.service.name in its configure()), OAuthBearerRefreshingLogin for OAUTHBEARER, and DefaultLogin for all others."
}

